import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.DocumentBuilder;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

public class TestDom {
    public static void main(String[] args) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true); // W3CDom sets this to true
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.newDocument();

        try {
            System.out.println("Attempting createElementNS(null, \"fb:like\")");
            Element el = doc.createElementNS(null, "fb:like");
            System.out.println("Success NS:");
            System.out.println("NodeName: " + el.getNodeName());
            System.out.println("LocalName: " + el.getLocalName());
            System.out.println("Namespace: " + el.getNamespaceURI());
        } catch (Exception e) {
            System.out.println("Failed NS: " + e.getClass().getName() + ": " + e.getMessage());
        }

        try {
            System.out.println("Attempting createElement(\"fb:like\")");
            Element el = doc.createElement("fb:like");
            System.out.println("Success NoNS:");
            System.out.println("NodeName: " + el.getNodeName());
            System.out.println("LocalName: " + el.getLocalName());
            System.out.println("Namespace: " + el.getNamespaceURI());
        } catch (Exception e) {
            System.out.println("Failed NoNS: " + e);
        }
    }
}

